import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinListTableConfigModal,
  Select,
  dispatchAppToast,
  LinPageLayout,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useCatalogTableBusy,
  type ErpListTableConfig,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { StageTrackingDto } from '../../../services/sx/models';
import { nangSuatPageLabels as labels } from '../../../constants/nangSuatPageLabels';
import { formatNumber, formatPercent } from '../../../utils/format';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useMesNangSuatReportPermissions } from '../../../hooks/useMesPermissions';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-nang-suat';
const PAGE_ID = 'sx-nang-suat';

interface ProductivityRow {
  stageId: string;
  stageName: string;
  totalOut: number;
  totalIn: number;
  totalDefect: number;
  efficiency: number;
}

function monthRange(month: number, year: number) {
  const from = new Date(year, month - 1, 1).toISOString().slice(0, 10);
  const to = new Date(year, month, 0).toISOString().slice(0, 10);
  return { from, to };
}

const NangSuatPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const perms = useMesNangSuatReportPermissions();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<StageTrackingDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [configOpen, setConfigOpen] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(`${TEST_ID}-report-table-config`),
  );

  const { showTableLoading } = useCatalogTableBusy(loading);

  const monthOptions = useMemo(
    () => Array.from({ length: 12 }, (_, i) => ({ value: String(i + 1), label: `Tháng ${i + 1}` })),
    [],
  );
  const yearOptions = useMemo(
    () => [year - 1, year, year + 1].map(y => ({ value: String(y), label: String(y) })),
    [year],
  );

  const handleLoad = useCallback(() => {
    setLoading(true);
    const { from, to } = monthRange(month, year);
    sxService
      .getStageTracking({ fromDate: from, toDate: to, page: 1, pageSize: 500 })
      .then(res => {
        setRows(res.items);
        setLoaded(true);
      })
      .catch(err => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.loadError),
          type: 'error',
        });
      })
      .finally(() => setLoading(false));
  }, [dispatch, month, year]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!cancelled) handleLoad();
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [handleLoad]);

  const aggregated = useMemo(() => {
    const map: Record<string, ProductivityRow> = {};
    for (const r of rows) {
      if (!map[r.stageId]) {
        map[r.stageId] = {
          stageId: r.stageId,
          stageName: r.stageName,
          totalOut: 0,
          totalIn: 0,
          totalDefect: 0,
          efficiency: 0,
        };
      }
      map[r.stageId].totalOut += r.outQty;
      map[r.stageId].totalIn += r.inQty;
      map[r.stageId].totalDefect += r.defectQty;
    }
    return Object.values(map).map(row => ({
      ...row,
      efficiency: formatPercent(row.totalOut, row.totalIn || row.totalOut || 1),
    }));
  }, [rows]);

  const totals = aggregated.reduce(
    (acc, r) => ({ out: acc.out + r.totalOut, in: acc.in + r.totalIn, defect: acc.defect + r.totalDefect }),
    { out: 0, in: 0, defect: 0 },
  );
  const avgEfficiency = formatPercent(totals.out, totals.in || totals.out || 1);

  const handleSaveTableConfig = (next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(`${TEST_ID}-report-table-config`, next);
  };

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleLoad}
        searchAriaLabel={labels.view}
        loading={loading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-month`}>
              <Select
                label={labels.monthLabel}
                value={String(month)}
                onChange={e => setMonth(Number(e.target.value))}
                options={monthOptions}
                size="small"
              />
            </div>
            <div data-testid={`${TEST_ID}-field-year`}>
              <Select
                label={labels.yearLabel}
                value={String(year)}
                onChange={e => setYear(Number(e.target.value))}
                options={yearOptions}
                size="small"
              />
            </div>
          </>
        )}
      />
    ),
    [month, year, monthOptions, yearOptions, handleLoad, loading],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: () => {
        if (perms.canRead) handleLoad();
      },
      canPrint: perms.canPrint && loaded && aggregated.length > 0,
      onPrint: () => window.print(),
      onEditConfig: perms.canConfig ? () => setConfigOpen(true) : undefined,
    }),
    [handleLoad, loaded, aggregated.length, perms],
  );

  const listBody =
    !showTableLoading && aggregated.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colStage}</th>
              <th className={erp.colRight}>{labels.colInQty}</th>
              <th className={erp.colRight}>{labels.colOutQty}</th>
              <th className={erp.colRight}>{labels.colDefectQty}</th>
              <th className={erp.colRight}>{labels.colEfficiency}</th>
            </tr>
          </thead>
          <tbody>
            {aggregated.map(r => (
              <tr key={r.stageId} data-testid={`${TEST_ID}-row-${r.stageId}`}>
                <td>{r.stageName}</td>
                <td className={erp.colRight}>{formatNumber(r.totalIn)}</td>
                <td className={erp.colRight}>{formatNumber(r.totalOut)}</td>
                <td className={erp.colRight}>{formatNumber(r.totalDefect)}</td>
                <td className={erp.colRight}>
                  <span
                    style={{
                      color: r.efficiency >= 100 ? '#217A3C' : r.efficiency >= 80 ? '#d46b08' : '#C33A00',
                      fontWeight: 600,
                    }}
                  >
                    {r.efficiency}%
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div className={erp.voucherListRoot} data-report-list-page data-testid={`${TEST_ID}-list`}>
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          subTitle: `${labels.subtitle} — T${month}/${year}`,
          titleIconClass: 'fas fa-chart-line',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={
          loaded && aggregated.length > 0 ? (
            <div className={erp.paginationRow}>
              <span className={erp.summaryItem}>
                {labels.summaryOut}: <strong>{formatNumber(totals.out)}</strong>
              </span>
              <span className={erp.summaryItem}>
                {labels.summaryEfficiency}: <strong>{avgEfficiency}%</strong>
              </span>
              <span className={erp.summaryItem}>
                {labels.summaryDefect}: <strong>{formatNumber(totals.defect)}</strong>
              </span>
              <span className={erp.totalCount}>
                {labels.summaryStages}: {aggregated.length}
              </span>
            </div>
          ) : undefined
        }
        modals={
          <LinListTableConfigModal
            isOpen={configOpen}
            onClose={() => setConfigOpen(false)}
            testIdPrefix={TEST_ID}
            config={tableConfig}
            onSave={handleSaveTableConfig}
          />
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default NangSuatPage;
